INSERT INTO `surveys_questionnairetemplate` VALUES (1,'SCL-90 示例（10题）','scl90_sample','用于演示系统闭环的示例问卷（非正式量表题干）。','[{\"id\": 1, \"max\": 5, \"min\": 1, \"text\": \"示例题：最近我感到紧张不安。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 2, \"max\": 5, \"min\": 1, \"text\": \"示例题：我很难放松下来。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 3, \"max\": 5, \"min\": 1, \"text\": \"示例题：我对以前感兴趣的事提不起劲。\", \"weight\": 1, \"dimension\": \"depression\"}, {\"id\": 4, \"max\": 5, \"min\": 1, \"text\": \"示例题：我觉得做什么都很累。\", \"weight\": 1, \"dimension\": \"depression\"}, {\"id\": 5, \"max\": 5, \"min\": 1, \"text\": \"示例题：我最近睡眠质量不佳。\", \"weight\": 1, \"dimension\": \"sleep\"}, {\"id\": 6, \"max\": 5, \"min\": 1, \"text\": \"示例题：我经常难以入睡或易醒。\", \"weight\": 1, \"dimension\": \"sleep\"}, {\"id\": 7, \"max\": 5, \"min\": 1, \"text\": \"示例题：我在人际相处中感到压力。\", \"weight\": 1, \"dimension\": \"social\"}, {\"id\": 8, \"max\": 5, \"min\": 1, \"text\": \"示例题：我担心别人对我的看法。\", \"weight\": 1, \"dimension\": \"social\"}, {\"id\": 9, \"max\": 5, \"min\": 1, \"text\": \"示例题：我最近食欲变化明显。\", \"weight\": 1, \"dimension\": \"somatic\"}, {\"id\": 10, \"max\": 5, \"min\": 1, \"text\": \"示例题：我常感到身体不适但查不出原因。\", \"weight\": 1, \"dimension\": \"somatic\"}]','2026-01-31 23:54:50.737305'),(2,'SCL-90 结构化模拟量表（90题）','scl90_sample','结构化模拟题库（非版权原题），用于流程联调与模型接口验证。','[{\"id\": 1, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题01：最近一周我常有不明原因的头痛或身体酸痛。\", \"weight\": 1, \"dimension\": \"somatization\"}, {\"id\": 2, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题02：最近一周我会反复感到胃部不适或食欲异常。\", \"weight\": 1, \"dimension\": \"somatization\"}, {\"id\": 3, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题03：最近一周我容易出现心慌、胸闷等身体反应。\", \"weight\": 1, \"dimension\": \"somatization\"}, {\"id\": 4, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题04：最近一周我经常感觉精力不足、身体沉重。\", \"weight\": 1, \"dimension\": \"somatization\"}, {\"id\": 5, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题05：最近一周我会担心自己身体出现严重问题。\", \"weight\": 1, \"dimension\": \"somatization\"}, {\"id\": 6, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题06：最近一周我会因为身体小毛病而明显紧张。\", \"weight\": 1, \"dimension\": \"somatization\"}, {\"id\": 7, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题07：最近一周我常感到四肢乏力或发软。\", \"weight\": 1, \"dimension\": \"somatization\"}, {\"id\": 8, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题08：最近一周我会被睡眠相关的身体不适困扰。\", \"weight\": 1, \"dimension\": \"somatization\"}, {\"id\": 9, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题09：最近一周我的身体状态影响了学习/生活节奏。\", \"weight\": 1, \"dimension\": \"somatization\"}, {\"id\": 10, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题10：最近一周我会反复检查同一件事是否完成。\", \"weight\": 1, \"dimension\": \"compulsive\"}, {\"id\": 11, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题11：最近一周我很难停止脑中重复出现的念头。\", \"weight\": 1, \"dimension\": \"compulsive\"}, {\"id\": 12, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题12：最近一周我做事会过度追求完美而拖延。\", \"weight\": 1, \"dimension\": \"compulsive\"}, {\"id\": 13, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题13：最近一周我常因担心出错而重复确认细节。\", \"weight\": 1, \"dimension\": \"compulsive\"}, {\"id\": 14, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题14：最近一周我会反复回想已发生的小失误。\", \"weight\": 1, \"dimension\": \"compulsive\"}, {\"id\": 15, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题15：最近一周我在学习时常被“必须这样做”困住。\", \"weight\": 1, \"dimension\": \"compulsive\"}, {\"id\": 16, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题16：最近一周我会因反复犹豫而难以下决定。\", \"weight\": 1, \"dimension\": \"compulsive\"}, {\"id\": 17, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题17：最近一周我会按固定顺序做事，否则不安。\", \"weight\": 1, \"dimension\": \"compulsive\"}, {\"id\": 18, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题18：最近一周我会因反复整理/重做而耗费很多时间。\", \"weight\": 1, \"dimension\": \"compulsive\"}, {\"id\": 19, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题19：最近一周我在人际互动中容易紧张或不自在。\", \"weight\": 1, \"dimension\": \"interpersonal\"}, {\"id\": 20, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题20：最近一周我会过度在意别人对我的看法。\", \"weight\": 1, \"dimension\": \"interpersonal\"}, {\"id\": 21, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题21：最近一周我与同学沟通时担心被否定。\", \"weight\": 1, \"dimension\": \"interpersonal\"}, {\"id\": 22, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题22：最近一周我会因为社交场合而感到明显压力。\", \"weight\": 1, \"dimension\": \"interpersonal\"}, {\"id\": 23, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题23：最近一周我在人多场景里容易感到拘谨。\", \"weight\": 1, \"dimension\": \"interpersonal\"}, {\"id\": 24, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题24：最近一周我会避免主动表达自己的真实想法。\", \"weight\": 1, \"dimension\": \"interpersonal\"}, {\"id\": 25, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题25：最近一周我在人际冲突后会持续自责。\", \"weight\": 1, \"dimension\": \"interpersonal\"}, {\"id\": 26, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题26：最近一周我感觉自己不太容易被他人理解。\", \"weight\": 1, \"dimension\": \"interpersonal\"}, {\"id\": 27, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题27：最近一周我与他人相处时常感到被比较或被评判。\", \"weight\": 1, \"dimension\": \"interpersonal\"}, {\"id\": 28, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题28：最近一周我对原本感兴趣的事情提不起劲。\", \"weight\": 1, \"dimension\": \"depression\"}, {\"id\": 29, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题29：最近一周我经常感到情绪低落或无助。\", \"weight\": 1, \"dimension\": \"depression\"}, {\"id\": 30, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题30：最近一周我会觉得做什么都没有意义。\", \"weight\": 1, \"dimension\": \"depression\"}, {\"id\": 31, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题31：最近一周我比平时更容易疲惫、动力不足。\", \"weight\": 1, \"dimension\": \"depression\"}, {\"id\": 32, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题32：最近一周我会对自己产生明显否定感。\", \"weight\": 1, \"dimension\": \"depression\"}, {\"id\": 33, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题33：最近一周我常觉得未来看起来缺乏希望。\", \"weight\": 1, \"dimension\": \"depression\"}, {\"id\": 34, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题34：最近一周我难以从日常小事中感到愉快。\", \"weight\": 1, \"dimension\": \"depression\"}, {\"id\": 35, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题35：最近一周我会持续处在压抑的心情中。\", \"weight\": 1, \"dimension\": \"depression\"}, {\"id\": 36, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题36：最近一周我会因为情绪问题影响学习效率。\", \"weight\": 1, \"dimension\": \"depression\"}, {\"id\": 37, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题37：最近一周我经常感到紧张、担忧难以放松。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 38, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题38：最近一周我会因为小事反复焦虑。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 39, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题39：最近一周我容易出现坐立不安的状态。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 40, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题40：最近一周我会对未发生的事情提前担心。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 41, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题41：最近一周我在压力情境下容易慌乱。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 42, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题42：最近一周我难以让自己平静下来。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 43, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题43：最近一周我会因学习任务产生持续焦虑感。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 44, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题44：最近一周我在夜间更容易出现担心和烦躁。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 45, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题45：最近一周焦虑情绪已影响我的专注与休息。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 46, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题46：最近一周我比平时更容易烦躁或发脾气。\", \"weight\": 1, \"dimension\": \"hostility\"}, {\"id\": 47, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题47：最近一周我会对他人的言行产生明显不满。\", \"weight\": 1, \"dimension\": \"hostility\"}, {\"id\": 48, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题48：最近一周我常有“容易被激怒”的体验。\", \"weight\": 1, \"dimension\": \"hostility\"}, {\"id\": 49, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题49：最近一周我在人际摩擦中更难控制情绪。\", \"weight\": 1, \"dimension\": \"hostility\"}, {\"id\": 50, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题50：最近一周我会因小冲突持续生气。\", \"weight\": 1, \"dimension\": \"hostility\"}, {\"id\": 51, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题51：最近一周我对周围环境更容易产生敌意。\", \"weight\": 1, \"dimension\": \"hostility\"}, {\"id\": 52, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题52：最近一周我会在沟通中不自觉提高语气。\", \"weight\": 1, \"dimension\": \"hostility\"}, {\"id\": 53, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题53：最近一周我会因压力大而迁怒他人。\", \"weight\": 1, \"dimension\": \"hostility\"}, {\"id\": 54, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题54：最近一周我经常感觉心里憋闷、想发泄。\", \"weight\": 1, \"dimension\": \"hostility\"}, {\"id\": 55, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题55：最近一周我在特定场景会出现明显害怕感。\", \"weight\": 1, \"dimension\": \"phobic\"}, {\"id\": 56, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题56：最近一周我会因为陌生环境而回避出行。\", \"weight\": 1, \"dimension\": \"phobic\"}, {\"id\": 57, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题57：最近一周我在公开场合容易紧张到想逃离。\", \"weight\": 1, \"dimension\": \"phobic\"}, {\"id\": 58, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题58：最近一周我会担心某些情境发生失控。\", \"weight\": 1, \"dimension\": \"phobic\"}, {\"id\": 59, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题59：最近一周我会因恐惧而主动减少社交活动。\", \"weight\": 1, \"dimension\": \"phobic\"}, {\"id\": 60, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题60：最近一周我在人群密集处会明显不安。\", \"weight\": 1, \"dimension\": \"phobic\"}, {\"id\": 61, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题61：最近一周我会回避自己觉得“危险”的地点。\", \"weight\": 1, \"dimension\": \"phobic\"}, {\"id\": 62, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题62：最近一周我在考试/汇报前会出现强烈害怕。\", \"weight\": 1, \"dimension\": \"phobic\"}, {\"id\": 63, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题63：最近一周恐惧情绪已影响我正常安排。\", \"weight\": 1, \"dimension\": \"phobic\"}, {\"id\": 64, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题64：最近一周我会怀疑他人对我有负面意图。\", \"weight\": 1, \"dimension\": \"paranoid\"}, {\"id\": 65, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题65：最近一周我容易把中性言行理解成针对我。\", \"weight\": 1, \"dimension\": \"paranoid\"}, {\"id\": 66, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题66：最近一周我会担心别人背后议论自己。\", \"weight\": 1, \"dimension\": \"paranoid\"}, {\"id\": 67, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题67：最近一周我在人际中更容易保持防备状态。\", \"weight\": 1, \"dimension\": \"paranoid\"}, {\"id\": 68, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题68：最近一周我会对他人评价过度敏感。\", \"weight\": 1, \"dimension\": \"paranoid\"}, {\"id\": 69, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题69：最近一周我常担心自己被误解或被针对。\", \"weight\": 1, \"dimension\": \"paranoid\"}, {\"id\": 70, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题70：最近一周我对周围人的信任感有所下降。\", \"weight\": 1, \"dimension\": \"paranoid\"}, {\"id\": 71, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题71：最近一周我会反复揣测他人的真实想法。\", \"weight\": 1, \"dimension\": \"paranoid\"}, {\"id\": 72, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题72：最近一周我在团队协作中更难放松。\", \"weight\": 1, \"dimension\": \"paranoid\"}, {\"id\": 73, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题73：最近一周我会感到与周围人有明显疏离感。\", \"weight\": 1, \"dimension\": \"psychoticism\"}, {\"id\": 74, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题74：最近一周我偶尔会有不真实或恍惚的感觉。\", \"weight\": 1, \"dimension\": \"psychoticism\"}, {\"id\": 75, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题75：最近一周我会觉得自己的想法难被理解。\", \"weight\": 1, \"dimension\": \"psychoticism\"}, {\"id\": 76, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题76：最近一周我感到思路有时变得混乱。\", \"weight\": 1, \"dimension\": \"psychoticism\"}, {\"id\": 77, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题77：最近一周我会出现难以描述的怪异不适感。\", \"weight\": 1, \"dimension\": \"psychoticism\"}, {\"id\": 78, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题78：最近一周我会因心理压力感到“脱节”。\", \"weight\": 1, \"dimension\": \"psychoticism\"}, {\"id\": 79, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题79：最近一周我在情绪波动时会有失控担忧。\", \"weight\": 1, \"dimension\": \"psychoticism\"}, {\"id\": 80, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题80：最近一周我会觉得自己和环境不太协调。\", \"weight\": 1, \"dimension\": \"psychoticism\"}, {\"id\": 81, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题81：最近一周我经常感到内心紧绷又难以言说。\", \"weight\": 1, \"dimension\": \"psychoticism\"}, {\"id\": 82, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题82：最近一周我的睡眠质量明显下降。\", \"weight\": 1, \"dimension\": \"additional\"}, {\"id\": 83, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题83：最近一周我在起床后仍感到疲惫。\", \"weight\": 1, \"dimension\": \"additional\"}, {\"id\": 84, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题84：最近一周我的食欲较平时变化明显。\", \"weight\": 1, \"dimension\": \"additional\"}, {\"id\": 85, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题85：最近一周我会因情绪问题影响日常效率。\", \"weight\": 1, \"dimension\": \"additional\"}, {\"id\": 86, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题86：最近一周我更容易因小问题反复担忧。\", \"weight\": 1, \"dimension\": \"additional\"}, {\"id\": 87, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题87：最近一周我会对未来安排感到迷茫。\", \"weight\": 1, \"dimension\": \"additional\"}, {\"id\": 88, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题88：最近一周我难以维持稳定的学习节奏。\", \"weight\": 1, \"dimension\": \"additional\"}, {\"id\": 89, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题89：最近一周我会觉得身心都处在高压状态。\", \"weight\": 1, \"dimension\": \"additional\"}, {\"id\": 90, \"max\": 5, \"min\": 1, \"text\": \"SCL90模拟题90：最近一周我需要更多支持才能维持状态。\", \"weight\": 1, \"dimension\": \"additional\"}]','2026-02-06 11:12:16.194748'),(3,'SAS 结构化模拟量表（20题）','sas_sample','结构化模拟题库（非版权原题），包含反向计分标记。','[{\"id\": 1, \"max\": 4, \"min\": 1, \"text\": \"SAS模拟题01：我会无明显原因地感到紧张不安。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 2, \"max\": 4, \"min\": 1, \"text\": \"SAS模拟题02：我容易因为小事而心里发慌。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 3, \"max\": 4, \"min\": 1, \"text\": \"SAS模拟题03：我在安静时也会感到难以放松。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 4, \"max\": 4, \"min\": 1, \"text\": \"SAS模拟题04：我常担心不好的事情会发生在自己身上。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 5, \"max\": 4, \"min\": 1, \"text\": \"SAS模拟题05：我在学习任务前会过度紧张。\", \"weight\": 1, \"reverse\": true, \"dimension\": \"anxiety\"}, {\"id\": 6, \"max\": 4, \"min\": 1, \"text\": \"SAS模拟题06：我会出现坐立不安、难以静下来的情况。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 7, \"max\": 4, \"min\": 1, \"text\": \"SAS模拟题07：我常觉得心跳加快或有紧迫感。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 8, \"max\": 4, \"min\": 1, \"text\": \"SAS模拟题08：我会因未来不确定而持续担忧。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 9, \"max\": 4, \"min\": 1, \"text\": \"SAS模拟题09：我容易因为他人评价而焦虑。\", \"weight\": 1, \"reverse\": true, \"dimension\": \"anxiety\"}, {\"id\": 10, \"max\": 4, \"min\": 1, \"text\": \"SAS模拟题10：我在睡前常因担心而难以入睡。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 11, \"max\": 4, \"min\": 1, \"text\": \"SAS模拟题11：我经常感觉神经绷得很紧。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 12, \"max\": 4, \"min\": 1, \"text\": \"SAS模拟题12：我在压力下会明显烦躁。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 13, \"max\": 4, \"min\": 1, \"text\": \"SAS模拟题13：我会反复思考同一件担心的事。\", \"weight\": 1, \"reverse\": true, \"dimension\": \"anxiety\"}, {\"id\": 14, \"max\": 4, \"min\": 1, \"text\": \"SAS模拟题14：我在公共场合容易紧张。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 15, \"max\": 4, \"min\": 1, \"text\": \"SAS模拟题15：我会因学习节奏而感到持续焦虑。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 16, \"max\": 4, \"min\": 1, \"text\": \"SAS模拟题16：我常担心自己表现不够好。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 17, \"max\": 4, \"min\": 1, \"text\": \"SAS模拟题17：我在突发变化面前容易慌乱。\", \"weight\": 1, \"reverse\": true, \"dimension\": \"anxiety\"}, {\"id\": 18, \"max\": 4, \"min\": 1, \"text\": \"SAS模拟题18：我近期更容易疲惫且难以恢复。\", \"weight\": 1, \"dimension\": \"anxiety\"}, {\"id\": 19, \"max\": 4, \"min\": 1, \"text\": \"SAS模拟题19：我会因焦虑影响专注力。\", \"weight\": 1, \"reverse\": true, \"dimension\": \"anxiety\"}, {\"id\": 20, \"max\": 4, \"min\": 1, \"text\": \"SAS模拟题20：我总体上感觉焦虑程度较高。\", \"weight\": 1, \"dimension\": \"anxiety\"}]','2026-02-06 11:12:22.566808'),(4,'SDS 结构化模拟量表（20题）','sds_sample','结构化模拟题库（非版权原题），包含反向计分标记。','[{\"id\": 1, \"max\": 4, \"min\": 1, \"text\": \"SDS模拟题01：我最近情绪低落的时间变多了。\", \"weight\": 1, \"dimension\": \"depression\"}, {\"id\": 2, \"max\": 4, \"min\": 1, \"text\": \"SDS模拟题02：我对曾经喜欢的事情兴趣下降。\", \"weight\": 1, \"reverse\": true, \"dimension\": \"depression\"}, {\"id\": 3, \"max\": 4, \"min\": 1, \"text\": \"SDS模拟题03：我会觉得做事提不起精神。\", \"weight\": 1, \"dimension\": \"depression\"}, {\"id\": 4, \"max\": 4, \"min\":